defmodule SqlAdmin.Queries.AdminQuery do
  alias SqlAdmin.Repo
  
  @allowed_tables ~w(users posts comments)
  @allowed_columns %{
    "users" => ~w(id email role status created_at updated_at),
    "posts" => ~w(id title user_id status created_at updated_at),
    "comments" => ~w(id content post_id user_id created_at updated_at)
  }

  def execute_safe_query(table, columns, filters) when is_binary(table) and is_list(columns) do
    with :ok <- validate_table(table),
         :ok <- validate_columns(table, columns),
         {:ok, query, params} <- build_safe_query(table, columns, filters) do
      
      case Ecto.Adapters.SQL.query(Repo, query, params) do
        {:ok, %{rows: rows, columns: cols}} ->
          {:ok, map_results(cols, rows)}
        {:error, error} ->
          {:error, error}
      end
    end
  end

  def get_table_stats(table) when is_binary(table) do
    if table in @allowed_tables do
      query = """
      SELECT 
        COUNT(*) as total_count,
        COUNT(DISTINCT created_at::date) as days_with_records
      FROM #{table}
      """
      
      case Ecto.Adapters.SQL.query(Repo, query, []) do
        {:ok, %{rows: [[total, days]]}} ->
          {:ok, %{total_count: total, days_with_records: days}}
        {:error, error} ->
          {:error, error}
      end
    else
      {:error, :invalid_table}
    end
  end

  def aggregate_by_field(table, field, aggregate_func) 
      when table in @allowed_tables and aggregate_func in ~w(count sum avg min max) do
    
    allowed_fields = Map.get(@allowed_columns, table, [])
    
    if field in allowed_fields do
      query = case aggregate_func do
        "count" -> "SELECT #{field}, COUNT(*) as count FROM #{table} GROUP BY #{field} ORDER BY count DESC"
        "sum" -> "SELECT #{field}, SUM(#{field}) as sum FROM #{table} GROUP BY #{field}"
        "avg" -> "SELECT #{field}, AVG(#{field}) as avg FROM #{table} GROUP BY #{field}"
        "min" -> "SELECT MIN(#{field}) as min FROM #{table}"
        "max" -> "SELECT MAX(#{field}) as max FROM #{table}"
      end
      
      case Ecto.Adapters.SQL.query(Repo, query, []) do
        {:ok, %{rows: rows, columns: columns}} ->
          {:ok, map_results(columns, rows)}
        {:error, error} ->
          {:error, error}
      end
    else
      {:error, :invalid_field}
    end
  end

  defp validate_table(table) do
    if table in @allowed_tables do
      :ok
    else
      {:error, :invalid_table}
    end
  end

  defp validate_columns(table, columns) do
    allowed = Map.get(@allowed_columns, table, [])
    
    if Enum.all?(columns, &(&1 in allowed)) do
      :ok
    else
      {:error, :invalid_columns}
    end
  end

  defp build_safe_query(table, columns, filters) do
    column_list = Enum.join(columns, ", ")
    base_query = "SELECT #{column_list} FROM #{table}"
    
    {where_clause, params} = build_filter_clause(table, filters)
    
    query = if where_clause != "" do
      base_query <> " WHERE " <> where_clause
    else
      base_query
    end
    
    {:ok, query, params}
  end

  defp build_filter_clause(table, filters) when is_map(filters) do
    allowed = Map.get(@allowed_columns, table, [])
    
    {conditions, params} = 
      filters
      |> Enum.filter(fn {key, _value} -> to_string(key) in allowed end)
      |> Enum.with_index(1)
      |> Enum.reduce({[], []}, fn {{key, value}, index}, {conds, prms} ->
        {["#{key} = $#{index}" | conds], [value | prms]}
      end)
    
    where_clause = conditions |> Enum.reverse() |> Enum.join(" AND ")
    {where_clause, Enum.reverse(params)}
  end
  defp build_filter_clause(_table, _filters), do: {"", []}

  defp map_results(columns, rows) do
    Enum.map(rows, fn row ->
      columns
      |> Enum.zip(row)
      |> Enum.into(%{})
    end)
  end
end

# lib/sql_admin/queries/report_query.ex
defmodule SqlAdmin.Queries.ReportQuery do
  alias SqlAdmin.Repo

  def user_activity_report(start_date, end_date) do
    query = """
    SELECT 
      u.id,
      u.email,
      u.role,
      COUNT(DISTINCT p.id) as post_count,
      COUNT(DISTINCT c.id) as comment_count
    FROM users u
    LEFT JOIN posts p ON p.user_id = u.id AND p.created_at BETWEEN $1 AND $2
    LEFT JOIN comments c ON c.user_id = u.id AND c.created_at BETWEEN $1 AND $2
    WHERE u.created_at <= $2
    GROUP BY u.id, u.email, u.role
    ORDER BY post_count DESC, comment_count DESC
    LIMIT 100
    """
    
    case Ecto.Adapters.SQL.query(Repo, query, [start_date, end_date]) do
      {:ok, %{rows: rows, columns: columns}} ->
        {:ok, map_results(columns, rows)}
      {:error, error} ->
        {:error, error}
    end
  end

  def daily_registrations(days_back) when is_integer(days_back) and days_back > 0 and days_back <= 365 do
    query = """
    SELECT 
      DATE(created_at) as date,
      COUNT(*) as registrations
    FROM users
    WHERE created_at >= CURRENT_DATE - INTERVAL '1 day' * $1
    GROUP BY DATE(created_at)
    ORDER BY date DESC
    """
    
    case Ecto.Adapters.SQL.query(Repo, query, [days_back]) do
      {:ok, %{rows: rows, columns: columns}} ->
        {:ok, map_results(columns, rows)}
      {:error, error} ->
        {:error, error}
    end
  end

  defp map_results(columns, rows) do
    Enum.map(rows, fn row ->
      columns
      |> Enum.zip(row)
      |> Enum.into(%{})
    end)
  end
end

